func (s *Store) Top(limit int) []URL {
	s.mu.RLock()
	defer s.mu.RUnlock()

	out := make([]URL, 0, len(s.urls))
	for _, u := range s.urls {
		out = append(out, *u)
	}

	sort.Slice(out, func(i, j int) bool {
		if out[i].Clicks == out[j].Clicks {
			return out[i].CreatedAt.Before(out[j].CreatedAt)
		}
		return out[i].Clicks > out[j].Clicks
	})

	if limit <= 0 || limit > len(out) {
		limit = len(out)
	}
	return out[:limit]
}

func (h *Handler) GetTopURLs(w http.ResponseWriter, r *http.Request) {
	if r.Method != http.MethodGet {
		writeError(w, http.StatusMethodNotAllowed, "method not allowed")
		return
	}
	if r.URL.Path != "/urls/top" {
		writeError(w, http.StatusNotFound, "not found")
		return
	}

	limit := 10
	if v := strings.TrimSpace(r.URL.Query().Get("limit")); v != "" {
		if n, err := strconv.Atoi(v); err == nil && n >= 0 {
			limit = n
		}
	}

	urls := h.store.Top(limit)
	resp := make([]StatsResponse, 0, len(urls))
	for _, u := range urls {
		resp = append(resp, StatsResponse{
			Code:        u.Code,
			OriginalURL: u.OriginalURL,
			ShortURL:    u.ShortURL,
			CreatedAt:   u.CreatedAt,
			Clicks:      u.Clicks,
		})
	}
	writeJSON(w, http.StatusOK, resp)
}

if r.URL.Path == "/urls" {
	handler.ListURLs(w, r)
	return
}
if strings.HasPrefix(r.URL.Path, "/urls/top") {
	handler.GetTopURLs(w, r)
	return
}
